async (params, browser) => {
  // Open shop page
  await browser.open(`https://www.etsy.com/shop/${params.shop_name}`)

  // Wait for shop page to load
  await browser.waitForSelector('h1, [data-shop-name], .v2-listing-card, a.listing-link', 15000)

  // Let page fully render
  await browser.wait(2000)

  // Scroll to load listings
  await browser.scroll({ direction: 'down', amount: 1000 })

  await browser.wait(1500)

  // Scroll further down
  await browser.scroll({ direction: 'down', amount: 1000 })

  await browser.wait(1500)

  // Extract shop profile
  const shop_data = await browser.evaluate(`const nameEl = document.querySelector('h1, [data-shop-name]'); const descriptionEl = document.querySelector('[data-id="about-section"], [aria-label*="announcement"], [data-shop-announcement]'); const salesEl = document.querySelector('[aria-label*="sale"], span[title*="sale"]'); const ratingEl = document.querySelector('input[name="rating"], [data-rating], [aria-label*="star rating"]'); const reviewCountEl = document.querySelector('a[href*="reviews"] span, a[href*="#reviews"]'); const locationEl = document.querySelector('[data-shop-location], [aria-label*="location"]'); const imgEl = document.querySelector('img[alt*="shop"][src*="etsystatic"], img[aria-label*="shop"]'); const memberSinceEl = document.querySelector('[aria-label*="member since"], [data-member-since]'); const ownerEl = document.querySelector('a[href*="/people/"], [data-shop-owner]'); const listings = []; const listingEls = document.querySelectorAll('.v2-listing-card, li[data-listing-id]'); for (let i = 0; i < Math.min(listingEls.length, 12); i++) { const el = listingEls[i]; const titleEl = el.querySelector('h2.v2-listing-card__title, h3.v2-listing-card__title, h2, h3, a[title]'); const priceEl = el.querySelector('span.currency-value, [data-currency-value]'); const currencyEl = el.querySelector('span.currency-symbol'); const linkEl = el.querySelector('a.listing-link, a[href*="/listing/"]'); const imgEl = el.querySelector('img'); listings.push({ title: titleEl ? (titleEl.getAttribute('title') || titleEl.textContent.trim()) : '', price: (currencyEl ? currencyEl.textContent.trim() : '') + (priceEl ? priceEl.textContent.trim() : ''), url: linkEl ? linkEl.href : '', image: imgEl ? imgEl.getAttribute('src') : '' }); } const sectionEls = document.querySelectorAll('nav a[href*="section_id"], [data-section-id] a'); const sections = []; sectionEls.forEach(function(el) { const text = el.textContent.trim(); if (text && text.length < 100) sections.push(text); }); return { name: nameEl ? nameEl.textContent.trim() : '' + params.shop_name + '', description: descriptionEl ? descriptionEl.textContent.trim().substring(0, 1000) : '', total_sales: salesEl ? salesEl.textContent.trim() : '', rating: ratingEl ? (ratingEl.getAttribute('value') || ratingEl.getAttribute('aria-label') || ratingEl.textContent.trim()) : '', review_count: reviewCountEl ? reviewCountEl.textContent.trim() : '', location: locationEl ? locationEl.textContent.trim() : '', owner: ownerEl ? ownerEl.textContent.trim() : '', member_since: memberSinceEl ? memberSinceEl.textContent.trim() : '', image: imgEl ? imgEl.getAttribute('src') : '', sections: sections.slice(0, 15), listing_count: listings.length, listings: listings, shop_url: window.location.href }`)

  return shop_data
}
